practice_tasks.solution:
import functools

def log_calls(func):
  @functools.wraps(func)
  def wrapper(*args, **kwargs):
    print('Calling function')
    return func(*args, **kwargs)
  return wrapper

@log_calls
def calculate_tax(amount):
  '''Calculates tax for an amount.'''
  return amount * 0.2

print(calculate_tax.__name__)

