import functools
import time

def time_it(func):
  @functools.wraps(func)
  def wrapper(*args, **kwargs):
    start = time.time()
    result = func(*args, **kwargs)
    print(f'Took {time.time() - start}s')
    return result
  return wrapper

@time_it
def process_data():
  '''Processes a bunch of data.'''
  pass
